SELECT c.coach_name AS coach_name, a.name AS athlete_name
FROM coaches c
JOIN athletes a ON c.coach_id = a.athlete_id;

SELECT name
FROM athletes
WHERE status = 'active';

SELECT name, club_id, ROW_NUMBER() OVER (ORDER BY club_id) AS row_number 
FROM athletes
WHERE status = 'active';

SELECT CAST(athlete_id AS TEXT) AS encoded_id
FROM athletes
WHERE athlete_id < 10;

SELECT club_id, next_club_id
FROM athlete_club_history
WHERE athlete_id = 1;

SELECT athlete_id, stat_name, value, date_recorded, category, unit, source
FROM athlete_statistics
WHERE stat_name = 'Most Wins' AND CAST(value AS INTEGER) > 3;
